<script src="js/webflow-script.js" type="text/javascript"></script>
<script src="js/gsap.min.js" type="text/javascript"></script>
<script src="js/scrolltrigger.min.js" type="text/javascript"></script>
<script src="js/splittext.min.js" type="text/javascript"></script>
<script src="https://unpkg.com/aos@2.3.1/dist/aos.js"></script>
<script src="https://cdnjs.cloudflare.com/ajax/libs/lightbox2/2.11.4/js/lightbox.min.js"></script>

<script type="text/javascript">
    AOS.init();
    gsap.registerPlugin(ScrollTrigger, SplitText);
    document.querySelectorAll(".w-tab-link").forEach(tab => {
        tab.addEventListener("click", function(e) {
            e.preventDefault();

            let tabName = this.getAttribute("data-w-tab");

            // remove active
            document.querySelectorAll(".w-tab-link").forEach(el => el.classList.remove("w--current"));
            document.querySelectorAll(".w-tab-pane").forEach(el => el.classList.remove("w--tab-active"));

            // add active
            this.classList.add("w--current");
            document.querySelector('.w-tab-pane[data-w-tab="' + tabName + '"]').classList.add("w--tab-active");
        });
    });
</script>
